CODE_EXAMPLE:
// Before
double calculateTotal() {
  double basePrice = quantity * itemPrice;
  if (basePrice > 1000) {
    return basePrice * 0.95;
  } else {
    return basePrice * 0.98;
  }
}

// After
double calculateTotal() {
  if (basePrice() > 1000) {
    return basePrice() * 0.95;
  } else {
    return basePrice() * 0.98;
  }
}

double basePrice() {
  return quantity * itemPrice;
}

UNIT_TEST_EXAMPLE:
@Test
public void testReplaceWithQuery() {
  Order order = new Order(100, 15); // quantity=100, itemPrice=15
  double total = order.calculateTotal();
  assertEquals(1425.0, total, 0.01);
}
